/**
 * Cleanup all [TEST] orders generated by load-test.mjs.
 * Matches by `full_name LIKE '[TEST]%'`.
 *
 * Run: node scripts/load-test-cleanup.mjs
 */

import { createClient } from '@supabase/supabase-js';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const here = dirname(fileURLToPath(import.meta.url));
const envText = readFileSync(join(here, '..', '.env.local'), 'utf8');
const env = Object.fromEntries(
  envText.split('\n').map(l => l.trim()).filter(l => l && !l.startsWith('#'))
    .map(l => { const i = l.indexOf('='); return [l.slice(0, i), l.slice(i + 1)]; })
);

const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY);

const { data, error } = await sb
  .from('orders')
  .select('id, order_number, full_name')
  .like('full_name', '[TEST]%');

if (error) { console.error(error); process.exit(1); }
console.log(`Found ${data.length} test orders to delete.`);

if (data.length === 0) process.exit(0);

const { error: delErr } = await sb
  .from('orders')
  .delete()
  .like('full_name', '[TEST]%');

if (delErr) { console.error(delErr); process.exit(1); }
console.log(`✅ Deleted ${data.length} test orders.`);
